import { toArray } from "../../utils/toArray.js";
import "../../utils/index.js";
//#region src/operations/policies/shared.ts
function makeClauses({ role, using, check }) {
	const roles = toArray(role).join(", ");
	const clauses = [];
	if (roles) clauses.push(`TO ${roles}`);
	if (using) clauses.push(`USING (${using})`);
	if (check) clauses.push(`WITH CHECK (${check})`);
	return clauses;
}
//#endregion
export { makeClauses };
